Invalid `new_str` parameter: void
EmitIR::operator()(VarDecl* obj)
{
  // 全局变量
  if (mCurFunc == nullptr) {
    auto ty = self(obj->type);
    llvm::Constant* initVal;
    if (obj->init)
      initVal = llvm::dyn_cast<llvm::Constant>(self(obj->init));
    else
      initVal = llvm::Constant::getNullValue(ty);
    auto gv = new llvm::GlobalVariable(
      mMod, ty, obj->type->qual.const_,
      llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
    obj->any = gv;
    return;
  }

  // 局部变量
  auto ty = self(obj->type);
  auto alloca = getOrCreateAlloca(ty, obj->name);
  obj->any = alloca;
  if (obj->init) {
    auto initVal = self(obj->init);
    mCurIrb->CreateStore(initVal, alloca);
  }
}. No replacement was performed. `new_str` and `old_str` must be different.
